31: /**
32:  * A {@link WindowAssigner} that windows elements into sessions based on the timestamp of the
33:  * elements. Windows cannot overlap.
34:  *
35:  * <p>For example, in order to window into windows with a dynamic time gap:
36:  *
37:  * <pre>{@code
38:  * DataStream<Tuple2<String, Integer>> in = ...;
39:  * KeyedStream<String, Tuple2<String, Integer>> keyed = in.keyBy(...);
40:  * WindowedStream<Tuple2<String, Integer>, String, TimeWindows> windowed =
41:  *   keyed.window(DynamicEventTimeSessionWindows.withDynamicGap({@link SessionWindowTimeGapExtractor }));
42:  * }</pre>
43:  *
44:  * @param <T> The type of the input elements
45:  */
46: @PublicEvolving
47: public class DynamicEventTimeSessionWindows<T> extends MergingWindowAssigner<T, TimeWindow> {
48:     private static final long serialVersionUID = 1L;
49: 
50:     protected SessionWindowTimeGapExtractor<T> sessionWindowTimeGapExtractor;
51: 
52:     protected DynamicEventTimeSessionWindows(
53:             SessionWindowTimeGapExtractor<T> sessionWindowTimeGapExtractor) {
54:         this.sessionWindowTimeGapExtractor = sessionWindowTimeGapExtractor;
55:     }
56: 
57:     @Override
58:     public Collection<TimeWindow> assignWindows(
59:             T element, long timestamp, WindowAssignerContext context) {
60:         long sessionTimeout = sessionWindowTimeGapExtractor.extract(element);
61:         if (sessionTimeout <= 0) {
62:             throw new IllegalArgumentException("Dynamic session time gap must satisfy 0 < gap");
63:         }
64:         return Collections.singletonList(new TimeWindow(timestamp, timestamp + sessionTimeout));
65:     }
66: 
67:     @SuppressWarnings("unchecked")
68:     @Override
69:     public Trigger<T, TimeWindow> getDefaultTrigger() {
70:         return (Trigger<T, TimeWindow>) EventTimeTrigger.create();
71:     }
72: 
73:     @Override
74:     public String toString() {
75:         return "DynamicEventTimeSessionWindows()";
76:     }
77: 
78:     /**
79:      * Creates a new {@code SessionWindows} {@link WindowAssigner} that assigns elements to sessions
80:      * based on the element timestamp.
81:      *
82:      * @param sessionWindowTimeGapExtractor The extractor to use to extract the time gap from the
83:      *     input elements
84:      * @return The policy.
85:      */
86:     public static <T> DynamicEventTimeSessionWindows<T> withDynamicGap(
87:             SessionWindowTimeGapExtractor<T> sessionWindowTimeGapExtractor) {
88:         return new DynamicEventTimeSessionWindows<>(sessionWindowTimeGapExtractor);
89:     }
90: 
91:     @Override
92:     public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
93:         return new TimeWindow.Serializer();
94:     }
95: 
96:     @Override
97:     public boolean isEventTime() {
98:         return true;
99:     }
100: 
101:     /** Merge overlapping {@link TimeWindow}s. */
102:     @Override
103:     public void mergeWindows(Collection<TimeWindow> windows, MergeCallback<TimeWindow> c) {
104:         TimeWindow.mergeWindows(windows, c);
105:     }
106: }
