            sessionStartTime = eventTime.toLocalDate().atTime(sessionOpen).atZone(timezone);
            sessionEndTime = eventTime.toLocalDate().atTime(sessionClose).atZone(timezone);
        } else if (eventLocalTime.isBefore(sessionOpen)) {
