    23→
    24→/**
    25→ * A {@link Trigger} that fires at market close (window end) via event-time timer. This trigger is
    26→ * designed to work with {@link
    27→ * org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow} to fire aggregations
    28→ * at the end of each trading session.
    29→ *
    30→ * <p>The trigger supports early firing on configurable events (e.g., circuit breaker halts) and
    31→ * properly handles window merging by re-registering timers when windows are merged.
    32→ *
    33→ * @see org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow
    34→ */
    35→@PublicEvolving
    36→public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    37→    private static final long serialVersionUID = 1L;
    38→
    39→    private PricingSessionTrigger() {}
    40→
    41→    @Override
    42→    public TriggerResult onElement(
    43→            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
    44→            throws Exception {
    45→        // Register a timer for the end of the trading session if not already past the watermark
    46→        if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
    47→            // If the watermark is already past the window fire immediately
    48→            return TriggerResult.FIRE;
    49→        } else {
    50→            // Register an event time timer at the window's end
    51→            ctx.registerEventTimeTimer(window.maxTimestamp());
    52→            return TriggerResult.CONTINUE;
    53→        }
    54→    }
    55→
    56→    @Override
    57→    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
    58→        // Fire when the event time reaches the window's end timestamp
    59→        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    60→    }
    61→
    62→    @Override
